/**
 * Standardized error definitions for Earn operations.
 *
 * These error codes provide fine-grained categorization of failures
 * from the Earn service, enabling SDK consumers to distinguish
 * between input errors (fix your request) and service errors (retry later).
 *
 * Error code ranges:
 * - 1100-1106: INPUT errors — invalid, unsupported, or stale request state
 * - 8100-8105: SERVICE errors — retryable backend/provider failures
 *
 * @example
 * ```typescript
 * import { EarnError, isInputError, isRetryableError } from '@circle-fin/earn-kit'
 *
 * try {
 *   await earnKit.deposit(params)
 * } catch (error) {
 *   if (isInputError(error)) {
 *     // Fix the request: vault doesn't exist, chain not supported, etc.
 *   }
 *   if (isRetryableError(error)) {
 *     // Try again: signing timed out, provider temporarily unavailable, etc.
 *   }
 * }
 * ```
 */ const EarnError = {
    /** The requested vault does not exist for the provided chain. */ VAULT_NOT_FOUND: {
        code: 1100,
        name: 'EARN_VAULT_NOT_FOUND',
        type: 'INPUT'
    },
    /** The specified blockchain is not supported for earn operations. */ UNSUPPORTED_CHAIN: {
        code: 1101,
        name: 'EARN_UNSUPPORTED_CHAIN',
        type: 'INPUT'
    },
    /** The vault's underlying asset is not supported. */ UNSUPPORTED_VAULT: {
        code: 1102,
        name: 'EARN_UNSUPPORTED_VAULT',
        type: 'INPUT'
    },
    /** The submitted signature could not be verified. */ SIGNATURE_REJECTED: {
        code: 1103,
        name: 'EARN_SIGNATURE_REJECTED',
        type: 'INPUT'
    },
    /** General input validation failure (invalid ID, batch size, etc.). */ INVALID_INPUT: {
        code: 1104,
        name: 'EARN_INVALID_INPUT',
        type: 'INPUT'
    },
    /**
   * The bridge quote expired. This is an INPUT error because the prepared
   * request is stale and must be replaced instead of retried.
   */ BRIDGE_QUOTE_EXPIRED: {
        code: 1106,
        name: 'EARN_BRIDGE_QUOTE_EXPIRED',
        type: 'INPUT'
    },
    /** The proxy signing call failed — retryable. */ SIGNING_FAILED: {
        code: 8100,
        name: 'EARN_SIGNING_FAILED',
        type: 'SERVICE'
    },
    /** An external provider API request failed — retryable. */ PROVIDER_ERROR: {
        code: 8101,
        name: 'EARN_PROVIDER_ERROR',
        type: 'SERVICE'
    },
    /** Failed to fetch reward data — retryable. */ REWARDS_FETCH_FAILED: {
        code: 8102,
        name: 'EARN_REWARDS_FETCH_FAILED',
        type: 'SERVICE'
    },
    /** An internal earn service error occurred — retryable. */ INTERNAL_ERROR: {
        code: 8103,
        name: 'EARN_INTERNAL_ERROR',
        type: 'SERVICE'
    },
    /** EarnKit interactions are temporarily paused off-chain — retryable. */ PAUSED: {
        code: 8104,
        name: 'EARN_PAUSED',
        type: 'SERVICE'
    },
    /** Position PnL is still reconciling and can be retried. */ POSITION_PNL_PENDING: {
        code: 8105,
        name: 'EARN_POSITION_PNL_PENDING',
        type: 'SERVICE'
    }
};

